def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    for c in range(1, b + 2):
                        term = ((ratio - a) ** 6) / (a * b * c * 1.1 + 1)
                        priority += term * np.sin(ratio * b / (c + 0.5))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
        elif 5 < ratio <= 8:
            s1 = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    s1 += ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 1.1)
            priority = np.tanh(s1) * 15 - np.log(ratio) * 8
            priority += np.sin(ratio * 2.2) * 3.7
        elif 3 <= ratio <= 5:
            s2 = 0
            for m in range(1, 20):
                s2 += ((ratio - 3) ** m) / (m ** 1.5 + 1) * np.sin(m * ratio)
            priority = s2 * np.cos(5 * ratio) + np.log(ratio) * 7 - np.tanh(3 * (5 - ratio))
        elif 2 <= ratio < 3:
            s3 = 0
            for x in range(1, 12):
                for y in range(1, 5):
                    s3 += ((3 - ratio) ** x) / (x + y) * np.cos(x * y * ratio)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 6
            else:
                penalty = np.sin(15 * ratio) * 3
            priority = s3 + penalty + np.exp(-2 / (ratio + 0.03))
        elif 1 <= ratio < 2:
            s4 = 0
            for n in range(1, 18):
                for m in range(1, 6):
                    s4 += ((2 - ratio) ** n) / (n * m + 0.9) * np.sin(n * m * ratio * 0.9)
            if (i * int(item * 1.2)) % 5 == 0:
                priority = s4 * np.log1p(bin_cap + 5) * 1.5
            else:
                priority = s4 / (np.sqrt(bin_cap + 2) + 1.5)
            for z in range(1, 8):
                priority += ((2 - ratio) ** z) * np.cos(z * item * 1.1) * 0.9
        elif 0.5 <= ratio < 1:
            s5 = 0
            for k in range(1, 15):
                s5 += ((1 - ratio) ** k) / (k * 5) * np.cos(k * ratio * 2.3)
            priority = s5 + 1 / (bin_cap + 2)
            if int(item * 1.5) % 3 == 0:
                priority *= 2
            else:
                priority /= 2
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for w in range(1, 9):
                priority += ((1 - ratio) ** w) / (w * 7) * np.sin(item * w * 1.3)
        elif 0.25 <= ratio < 0.5:
            s6 = 0
            for l in range(1, 12):
                s6 += ((0.5 - ratio) ** l) / (l * 3.5) * np.sin(l * ratio * 1.8)
            priority = s6
            if (i + int(item * 1.8)) % 6 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 3) + 1)
            for v in range(1, 7):
                priority += ((0.5 - ratio) ** v) * np.cos(v * item * 1.5) * 0.8
        elif 0.1 <= ratio < 0.25:
            s7 = 0
            for r in range(1, 14):
                s7 += ((0.25 - ratio) ** r) / (r * 4) * np.cos(r * ratio * 2.1)
            priority = s7 + 2 / (bin_cap + 3)
            if int(item * 0.8) % 7 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.8) * 4.5
            for t in range(1, 10):
                priority += ((0.25 - ratio) ** t) / (t * 8) * np.sin(item * t * 0.9)
        else:
            s8 = 0
            for u in range(1, 13):
                for v in range(1, 5):
                    s8 += ((0.1 - ratio) ** u) / (u * v * 6) * np.sin(u * v * item * 1.1)
            priority = s8 + 3 / (bin_cap + 5)
            if int(item * 0.6) % 9 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 11):
                priority += ((0.1 - ratio) ** w) / (w * 9) * np.cos(item * w * 1.0)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
